import React, { useState, useEffect, useRef } from 'react';
import { generateRandomBars } from './utils.js';

function AudioMark() {
  const canvasRef = useRef(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [bars, setBars] = useState(() => generateRandomBars(50));
  const animationRef = useRef(null);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const width = canvas.clientWidth;
    const height = canvas.clientHeight;
    canvas.width = width;
    canvas.height = height;

    ctx.clearRect(0, 0, width, height);
    const barWidth = width / bars.length;
    bars.forEach((heightValue, i) => {
      const x = i * barWidth;
      const y = canvas.height - (heightValue / 100) * canvas.height;
      ctx.fillStyle = `hsl(${200 + heightValue * 0.5}, 70%, 60%)`;
      ctx.fillRect(x, y, barWidth - 1, (heightValue / 100) * canvas.height);
    });
  };

  useEffect(() => {
    draw();
  }, [bars]);

  useEffect(() => {
    if (isPlaying) {
      const updateBars = () => {
        setBars(prev => prev.map(() => Math.random() * 100));
        animationRef.current = requestAnimationFrame(updateBars);
      };
      updateBars();
    } else {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    }
    return () => cancelAnimationFrame(animationRef.current);
  }, [isPlaying]);

  const togglePlay = () => setIsPlaying(!isPlaying);

  return (
    <div className="container">
      <h1>🎵 AudioMark Visualizer</h1>
      <canvas ref={canvasRef} style={{ width: '100%', height: '300px' }} />
      <button onClick={togglePlay}>{isPlaying ? '⏸ Pause' : '▶ Play'}</button>
      <div className="status">
        {isPlaying ? '🎶 Visualizing sound...' : '⚡ Click play to see random audio bars'}
      </div>
    </div>
  );
}

export default AudioMark;
